// eslint-disable-next-line import/order
import * as APM from 'elastic-apm-node';

import { AppModule } from '@app';
import {
  RequestMethod,
  ValidationPipe,
  VersioningType,
} from '@nestjs/common';
import { NestFactory } from '@nestjs/core';
import { NextFunction, Request, Response } from 'express';
import helmet from 'helmet';
import { WINSTON_MODULE_NEST_PROVIDER } from 'nest-winston';

import { appConfig, AppConfig } from '@infra/config';
import { ADLogger } from '@infra/logger';

import { ABBankWebHookModule } from '@modules/abb-webhook';

import { HttpExceptionFilter } from '@observables/filters';
import { TransformSensitiveValueInterceptor } from '@observables/interceptors';

import { setupSwagger, setupSwaggerForControllers } from '@utils/docs';

APM.start({
  environment: process.env.NODE_ENV,
  active: !!process.env.ELASTIC_APM_SERVICE_NAME,
});

async function bootstrap() {
  const app = await NestFactory.create(AppModule);
  const appConfigs = app.get<AppConfig>(appConfig.KEY);
  const logger = new ADLogger('bootstrap');
  const {
    env,
    schema,
    name,
    port,
    host,
    routePrefix,
    externalPort,
  } = appConfigs.app;

  if (appConfigs.logger.apm.enabled) {
    app.useLogger(app.get(WINSTON_MODULE_NEST_PROVIDER));
    // APM.start(); 
  }

  app.setGlobalPrefix(routePrefix, {
    exclude: [
      { path: 'health', method: RequestMethod.GET },
      { path: '/', method: RequestMethod.GET },
    ],
  });

  app.useGlobalPipes(new ValidationPipe(appConfigs.validationConfig));

  app.useGlobalInterceptors(new TransformSensitiveValueInterceptor());

  app.useGlobalFilters(new HttpExceptionFilter());

  app.use((req: Request, res: Response, next: NextFunction) => {
    if (req.originalUrl && req.originalUrl.split('/').pop() === 'favicon.ico') {
      return res.sendStatus(204);
    }
    next();
  });

  app.use(
    helmet({
      crossOriginEmbedderPolicy: false,
      contentSecurityPolicy: {
        directives: {
          defaultSrc: [`'self'`],
          styleSrc: [`'self'`, `'unsafe-inline'`],
          imgSrc: [`'self'`, 'data:', 'blob:', 'validator.swagger.io'],
          scriptSrc: [`'self'`, `https: 'unsafe-inline'`],
        },
      },
    }),
  );

  app.enableCors();

  app.enableVersioning({ type: VersioningType.URI });

  process.on('uncaughtException', (error) => {
    logger.error(error);
  });

  process.on('unhandledRejection', (error) => {
    logger.error(error);
  });

  if (appConfigs.swagger.enabled) {
    setupSwagger(app, appConfigs);
    setupSwaggerForControllers(app, appConfigs, [ABBankWebHookModule], 'api/abb-tech-specs');
  }

  const server = await app.listen(port, () => {
    const dbConfig = appConfigs.database;
    logger.log(
      `${name} listening at ${schema}://${host}:${externalPort} on ${env?.toUpperCase()} `,
    );
    logger.log(
      `Swagger listening at ${schema}://${host}:${externalPort}${appConfigs.swagger.route} `,
    );
    logger.log(
      `Postgres listening at ${`${dbConfig.host}:${dbConfig.port}`} db name: ${dbConfig.database} `,
    );
  });
  server.setTimeout(120000);
}
bootstrap();

