import { Injectable, Logger, LoggerService } from '@nestjs/common';

@Injectable()
export class ADLogger extends Logger implements LoggerService {
  constructor(context: string) {
    super(context);
  }
  private formatLog(msg: any, data?: any): [any, any?, any?] {
    const isElasticApmEnabled = !!process.env.ELASTIC_APM_SERVICE_NAME;
    const isJsonLogging = process.env.LOG_JSON === 'true';

    const normalizedMsg = typeof msg === 'object' && isJsonLogging ? JSON.stringify(msg) : msg || msg || '';
    const normalizedData = typeof data === 'object' && isJsonLogging ? JSON.stringify(data) : data || data || '';
    let message: any = normalizedMsg;

    if (isJsonLogging) {
      message = `${normalizedMsg} ${normalizedData}`;
    }
    if (isElasticApmEnabled) {
      return [{ message, context: this.context, data }];
    }

    return isJsonLogging ? [message] : !data ? [msg] : [msg, data];
  }

  log(message: any, data?: any) {
    super.log(...this.formatLog(message, data));
  }

  error(message: any, ...optionalParams: [...any, string?, string?]) {
    super.error(...this.formatLog(message, ...optionalParams));
  }

  warn(message: any, data?: any) {
    super.warn(...this.formatLog(message, data));
  }

  debug(message: any, data?: any) {
    super.debug(...this.formatLog(message, data));
  }

  verbose(message: any, data?: any) {
    super.verbose(...this.formatLog(message, data));
