+import { RedisClientType } from 'redis';
+
+import { ADLogger } from '@infra/logger';
+
+export function getRetryDelay(attempt: number, baseDelayMs: number, maxDelayMs: number) {
+  return Math.min(baseDelayMs * 2 ** Math.max(attempt - 1, 0), maxDelayMs);
+}
+
+export async function retryWithBackoff<T>({
+  attempts,
+  baseDelayMs,
+  maxDelayMs,
+  operationName,
+  execute,
+}: {
+  attempts: number;
+  baseDelayMs: number;
+  maxDelayMs: number;
+  operationName: string;
+  execute: () => Promise<T>;
+}): Promise<T> {
+  const logger = new ADLogger(operationName);
+  let lastError: unknown;
+
+  for (let attempt = 1; attempt <= attempts; attempt++) {
+    try {
+      return await execute();
+    } catch (error) {
+      lastError = error;
+
+      if (attempt >= attempts) {
+        break;
+      }
+
+      const retryInMs = getRetryDelay(attempt, baseDelayMs, maxDelayMs);
+      logger.warn(
+        `${operationName} failed on attempt ${attempt}/${attempts}, retrying in ${retryInMs}ms`,
+        error instanceof Error ? error.message : error,
+      );
+      await new Promise((resolve) => setTimeout(resolve, retryInMs));
+    }
+  }
+
+  throw lastError;
+}
+
+export function registerRedisClientLogging(
+  client: RedisClientType,
+  context: string,
+) {
+  const logger = new ADLogger(context);
+
+  client.on('connect', () => logger.log('Redis socket connected'));
+  client.on('ready', () => logger.log('Redis client ready'));
+  client.on('reconnecting', () => logger.warn('Redis reconnecting'));
+  client.on('end', () => logger.warn('Redis connection ended'));
+  client.on('error', (error) => logger.error('Redis client error', error instanceof Error ? error.stack : error));
+}
