+function isTransientDatabaseError(error: unknown): boolean {
+  if (!error || typeof error !== 'object') {
+    return false;
+  }
+
+  const candidate = error as Error & {
+    code?: string;
+    errno?: string;
+    cause?: unknown;
+    errors?: unknown[];
+  };
+
+  const transientMarkers = [
+    'econnrefused',
+    'connection terminated',
+    'timeout',
+    'terminating connection',
+    'the database system is starting up',
+    'could not connect',
+    'connection reset',
+    '57p01',
+  ];
+
+  const codes = [candidate.code, candidate.errno]
+    .filter((value): value is string => Boolean(value))
+    .map((value) => value.toLowerCase());
+  const message = (candidate.message || '').toLowerCase();
+
+  if (
+    codes.some((code) => transientMarkers.includes(code)) ||
+    transientMarkers.some((marker) => message.includes(marker))
+  ) {
+    return true;
+  }
+
+  if (Array.isArray(candidate.errors) && candidate.errors.some(isTransientDatabaseError)) {
+    return true;
+  }
+
+  if (candidate.cause) {
+    return isTransientDatabaseError(candidate.cause);
+  }
+
+  return false;
+}
+
+function shouldRetryDatabaseConnection(error: unknown) {
+  if (!(error instanceof Error)) {
+    return true;
+  }
+
+  return isTransientDatabaseError(error);
