import {
  ArgumentsHost,
  Catch,
  ExceptionFilter,
  HttpException,
} from '@nestjs/common';
import { Response } from 'express';

import { BaseResult } from '@utils/index';

@Catch(HttpException)
export class HttpExceptionFilter implements ExceptionFilter {
  catch(exception: HttpException, host: ArgumentsHost) {
    const result = new BaseResult<string>();
    const ctx = host.switchToHttp();
    const response = ctx.getResponse<Response>();

    const status = exception.getStatus();

    result.success = false;
    result.data = (exception as any).getResponse()?.data;
    result.message = (exception as any).getResponse()?.message || exception.message;
    result.errors = (exception as any).getResponse()?.error;
    response.status(status).json(result);
  }
}

