import { Injectable, OnModuleInit } from '@nestjs/common';
import { InjectDataSource } from '@nestjs/typeorm';
import { DataSource } from 'typeorm';

import { ADLogger } from '@infra/logger';

type PgPool = {
  on: (event: string, listener: (...args: any[]) => void) => void;
};

type PostgresDriverWithPool = {
  master?: PgPool;
};

@Injectable()
export class DatabaseConnectionMonitorService implements OnModuleInit {
  private readonly logger = new ADLogger(DatabaseConnectionMonitorService.name);
  private hasConnectedOnce = false;
  private wasDisconnected = false;

  constructor(
    @InjectDataSource()
    private readonly dataSource: DataSource,
  ) { }

  onModuleInit() {
    const driver = this.dataSource.driver as PostgresDriverWithPool;
    const pool = driver.master;

    if (!pool) {
      this.logger.warn('Postgres pool monitor was not attached because the pool is unavailable');
      return;
    }

    pool.on('connect', () => {
      if (this.wasDisconnected) {
        this.logger.log('Postgres reconnected');
        this.wasDisconnected = false;
        this.hasConnectedOnce = true;
        return;
      }

      if (!this.hasConnectedOnce) {
        this.logger.log('Postgres connected');
        this.hasConnectedOnce = true;
      }
    });

    pool.on('error', (error: unknown) => {
      this.wasDisconnected = true;
      this.logger.error(
        'Postgres connection lost',
        error instanceof Error ? error.stack : error,
      );
    });
  }
}

