import { catchError, firstValueFrom, retry, timeout } from 'rxjs';
import { HttpService } from '@nestjs/axios';
import { Processor, WorkerHost } from '@nestjs/bullmq';
import { AxiosError } from 'axios';
import { Job } from 'bullmq';

import { ADLogger } from '@infra/logger';

import { WebhookAuthPosition } from '@modules/company/entities';

import { PUSH_TRANSACTION_QUEUE, PushTransactionJobData } from './webhook.constants';

@Processor(PUSH_TRANSACTION_QUEUE, {
  concurrency: 3,
})
export class WebhookProcessor extends WorkerHost {
  private readonly logger = new ADLogger(WebhookProcessor.name);
  private readonly EXTERNAL_API_TIMEOUT = 15000; // 15s for external APIs
  private readonly RETRY_ATTEMPTS = 1; // Retry failed requests once

  constructor(
    private readonly httpService: HttpService,
  ) {
    super();
  }

  async process(job: Job<PushTransactionJobData>): Promise<any> {
    const {
      webhookApiKey,
      webhookUrl,
      webhookAuthKey,
      webhookAuthPosition,
      companyInfo,
    } = job.data;
    const body = { ...job.data.body };

    const query = new URLSearchParams();
    const headers = {
      'Content-Type': 'application/json',
    };

    if (webhookAuthPosition === WebhookAuthPosition.HEADERS) {
      headers[`${webhookAuthKey}`] = webhookApiKey;
    }
    if (webhookAuthPosition === WebhookAuthPosition.BODY) {
      body[`${webhookAuthKey}`] = webhookApiKey;
    }
    if (webhookAuthPosition === WebhookAuthPosition.QUERY) {
      query.append(`${webhookAuthKey}`, webhookApiKey);
    }

    this.logger.log(`pushTransaction:: calling ${companyInfo}) service: `, {
      webhookApiKey,
      webhookUrl,
      body,
      attemptsMade: job.attemptsMade,
    });
    const { data } = await firstValueFrom(
      this.httpService.post(webhookUrl + `?${query.toString()}`, body, { headers, timeout: this.EXTERNAL_API_TIMEOUT })
        .pipe(
          timeout(this.EXTERNAL_API_TIMEOUT),
          retry(this.RETRY_ATTEMPTS),
          catchError((error: AxiosError) => {
            const errorMsg = error?.response?.data || error?.message || error;
            this.logger.error(`pushTransaction:: calling ${companyInfo}) service failed: `,
              { error: errorMsg, webhookUrl },
            );
            throw new Error(`calling ${companyInfo}) service failed`);
          }),
        ),
    );
    this.logger.log(`pushTransaction:: calling ${companyInfo}) service response: `, data);

    return data;
  }
}

